const calculator = {
  BASE_COST: {
    concretePerYard: 150,
    rebarPerSqft: 1.5,
    deliveryPerMile: 3,
    minDelivery: 50,
  },

  validate(inputs) {
    const errors = [];

    // slabWidth
    const w = parseFloat(inputs.slabWidth);
    if (inputs.slabWidth === undefined || inputs.slabWidth === null || isNaN(w) || w <= 0) {
      errors.push('Width must be a number greater than 0');
    }

    // slabLength
    const l = parseFloat(inputs.slabLength);
    if (inputs.slabLength === undefined || inputs.slabLength === null || isNaN(l) || l <= 0) {
      errors.push('Length must be a number greater than 0');
    }

    // slabDepth (optional, default 4, but if provided must be positive number)
    const dProvided = inputs.slabDepth;
    if (dProvided !== undefined && dProvided !== null) {
      const d = parseFloat(dProvided);
      if (isNaN(d) || d <= 0) errors.push('Depth must be a number greater than 0');
    }

    // deliveryMiles
    const dm = inputs.deliveryMiles;
    if (dm === undefined || dm === null || isNaN(parseFloat(dm)) || parseFloat(dm) < 0) {
      errors.push('Delivery miles must be a number >= 0');
    }

    // rebarNeeded must be boolean
    if (typeof inputs.rebarNeeded !== 'boolean') {

    // rebarNeeded must be boolean
    if (typeof inputs.rebarNeeded !== 'boolean') {
      errors.push('Rebar needed must be true or false');
    }

    // wasteFactor validation (case-insensitive)
    const validWaste = ['waste_0', 'waste_5', 'waste_10', 'waste_15'];
    const wf = String(inputs.wasteFactor || 'waste_0').toLowerCase();
    if (!validWaste.includes(wf)) {
      errors.push('Invalid waste factor');
    }

    return errors.length === 0 ? null : errors[0];
  },

  calculate(inputs) {
    const error = this.validate(inputs);
    if (error) return { error };

    const w = parseFloat(inputs.slabWidth);
    const l = parseFloat(inputs.slabLength);
    const d = parseFloat(inputs.slabDepth || 4);
    const wf = String(inputs.wasteFactor || 'waste_0').toLowerCase();
    const wastePercent = parseInt(wf.replace('waste_', '')) || 0;
    const rebar = Boolean(inputs.rebarNeeded);
    const miles = parseFloat(inputs.deliveryMiles || 0);

    const volumeCY = (w * l * (d / 12)) / 27;
    const totalCY = volumeCY * (1 + wastePercent / 100);
    const concreteCost = totalCY * this.BASE_COST.concretePerYard;
    const rebarCost = rebar ? (w * l * this.BASE_COST.rebarPerSqft) : 0;
    const deliveryCost = Math.max(this.BASE_COST.minDelivery, miles * this.BASE_COST.deliveryPerMile);
    const total = Math.round((concreteCost + rebarCost + deliveryCost) * 100) / 100;

    return {
      total,
      breakdown: {
        volumeCY: parseFloat(volumeCY.toFixed(4)),
        totalCY: parseFloat(totalCY.toFixed(4)),
        wastePercent,
        concreteCost: parseFloat(concreteCost.toFixed(2)),
        rebarCost: parseFloat(rebarCost.toFixed(2)),
        deliveryCost: parseFloat(deliveryCost.toFixed(2)),
        total
      }
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  }
};

const CALC_PARAMS = [
  { name: 'slabWidth', label: 'Slab Width (ft)', type: 'number', placeholder: 'e.g. 10' },
  { name: 'slabLength', label: 'Slab Length (ft)', type: 'number', placeholder: 'e.g. 20' },
  { name: 'slabDepth', label: 'Slab Depth (inches)', type: 'number', placeholder: 'e.g. 4 (default)' },
  { name: 'wasteFactor', label: 'Waste Factor', type: 'select', options: [['waste_0', '0% — Perfect pour'], ['waste_5', '5% — Standard'], ['waste_10', '10% — Complex shape'], ['waste_15', '15% — Safety margin']] },
  { name: 'rebarNeeded', label: '🧱 Need Rebar?', type: 'checkbox' },
  { name: 'deliveryMiles', label: 'Delivery (miles)', type: 'number', placeholder: 'e.g. 10' }
];
